template:
const std = @import("std");

pub const Expr = [[SLOT union_kw]] {
    number: i32,
    add: struct {
        left: *const Expr,
        right: *const Expr,
    },
    multiply: struct {
        left: *const Expr,
        right: *const Expr,
    },
};

pub fn evaluate(expr: Expr) i32 {
    return switch (expr) {
        .number => |n| [[SLOT num_eval]],
        .add => |op| [[SLOT add_eval]],
        .multiply => |op| [[SLOT mul_eval]],
    };
}
